def get_gold_answer_text(item: dict) -> str:
    if item.get("gold_answer"):
        return str(item.get("gold_answer")).strip()

    options = item.get("options") or {}
    right_option = (item.get("right_option") or "").strip().upper()
    if right_option and right_option in options:
        return str(options[right_option]).strip()

    if right_option:
        return right_option
    return ""


def parse_judge_output(raw: str) -> tuple[int, str]:
    text = (raw or "").strip()
    if not text:
        return 0, "empty judge output"

    try:
        payload = json.loads(text)
        verdict = str(payload.get("verdict", "")).strip().upper()
        if verdict == "CORRECT":
            return 1, str(payload.get("reason", ""))
        if verdict == "INCORRECT":
            return 0, str(payload.get("reason", ""))
    except Exception:
        pass

    m = re.search(r"\{.*\}", text, flags=re.S)
    if m:
        try:
            payload = json.loads(m.group(0))
            verdict = str(payload.get("verdict", "")).strip().upper()
            if verdict == "CORRECT":
                return 1, str(payload.get("reason", ""))
            if verdict == "INCORRECT":
                return 0, str(payload.get("reason", ""))
        except Exception:
            pass

    upper = text.upper()
    if "CORRECT" in upper and "INCORRECT" not in upper:
        return 1, "fallback keyword parse"
    return 0, "fallback keyword parse"


def judge_short_answer(client: OpenAI, item: dict, prediction: str) -> dict:
    gold = get_gold_answer_text(item)
    if not prediction.strip():
        return {"acc": 0, "reason": "empty prediction", "gold_answer": gold, "judge_raw": ""}

    messages = [
        {
            "role": "system",
            "content": (
                "You are a strict medical QA grader. Compare the model answer against the gold diagnosis. "
                "Accept close clinical synonyms and equivalent specificity, reject different diagnoses. "
                "Return JSON only: {\"verdict\":\"CORRECT\"|\"INCORRECT\",\"reason\":\"...\"}."
            ),
        },
        {
            "role": "user",
            "content": (
                "Case:\n"
                f"{item.get('case_information', '')}\n\n"
                "Gold diagnosis:\n"
                f"{gold}\n\n"
                "Model diagnosis:\n"
                f"{prediction}\n"
            ),
        },
    ]
    raw = run_model(client, messages, JUDGE_MODEL)
    acc, reason = parse_judge_output(raw)
    return {"acc": acc, "reason": reason, "gold_answer": gold, "judge_raw": raw}


