def eval_all_exams_once(client: OpenAI, item: dict) -> dict:
    all_exams = item.get("structured_examinations") or {}
    all_exams_text = "\n".join(f"{k}: {v}" for k, v in all_exams.items()) or "(none)"

    prompt = f"""You are solving a medical diagnosis short-answer task.

Reply with exactly two XML tags and nothing else.

Format:
<think>
brief reasoning
</think>
<answer>FINAL_DIAGNOSIS_TEXT</answer>

Case Information:
{item.get("case_information", "")}

Physical Examination:
{item.get("physical_examination", "")}

All Examination Results:
{all_exams_text}
"""

    messages = [
        {
            "role": "system",
            "content": (
                "Return only <think> and <answer> tags. "
                "Put only the final diagnosis text inside <answer>...</answer>."
            ),
        },
        {"role": "user", "content": prompt},
    ]
    raw = ""
    for attempt in range(ALL_EXAMS_ONCE_RETRIES + 1):
        try:
            raw = run_model(client, messages, MODEL)
        except Exception:
            raw = ""
        if not is_bad_all_exams_once_raw(raw):
            break
        if attempt < ALL_EXAMS_ONCE_RETRIES:
            time.sleep(RETRY_SLEEP_BASE_SEC * (attempt + 1))

    pred = answer_text(raw)
    judge = judge_short_answer(client, item, pred)

    return {
        "answer": pred,
        "gold_answer": judge.get("gold_answer", ""),
        "judge": {
            "acc": judge.get("acc", 0),
            "reason": judge.get("reason", ""),
            "raw": judge.get("judge_raw", ""),
            "model": JUDGE_MODEL,
        },
        "score": {"acc": judge.get("acc", 0)},
        "raw_conversation": {"messages": messages, "raw": raw},
    }


def eval_one(client: OpenAI, item: dict) -> dict:
    out = dict(item)
    out["multiround"] = eval_multiround(client, item)
    out["all_exams_once"] = eval_all_exams_once(client, item)
    return out


def aggregate(items: list[dict]) -> dict:
    n = len(items)
    m_acc = 0.0
    m_precision = 0.0
    m_recall = 0.0
    m_f1 = 0.0
    m_pred_enough = 0
    m_pred_not_enough = 0
    m_pred_format_error = 0
    all_exams_acc = 0.0

    for item in items:
        m = item.get("multiround", {})
        s = m.get("score", {})
        m_acc += s.get("acc", 0.0)
        m_precision += s.get("precision", 0.0)
        m_recall += s.get("recall", 0.0)
        m_f1 += s.get("f1", 0.0)

        mode = m.get("final_mode")
        m_pred_enough += int(mode == "ENOUGH")
        m_pred_not_enough += int(mode == "NOT ENOUGH")
        m_pred_format_error += int(mode not in {"ENOUGH", "NOT ENOUGH"})

        all_exams_acc += item.get("all_exams_once", {}).get("score", {}).get("acc", 0.0)

    if n == 0:
        return {
            "count": 0,
            "multiround": {
                "acc": None,
                "precision": None,
                "recall": None,
                "f1": None,
                "pred_enough": 0,
                "pred_not_enough": 0,
                "pred_format_error": 0,
            },
            "all_exams_once": {"acc": None},
        }

    return {
        "count": n,
        "multiround": {
            "acc": m_acc / n,
            "precision": m_precision / n,
            "recall": m_recall / n,
            "f1": m_f1 / n,
            "pred_enough": m_pred_enough,
            "pred_not_enough": m_pred_not_enough,
            "pred_format_error": m_pred_format_error,
        },
        "all_exams_once": {
            "acc": all_exams_acc / n,
        },
    }


def main() -> None:
    client = OpenAI(api_key=OPENAI_API_KEY, base_url=OPENAI_BASE_URL)
    with open(INPUT_PATH, "r", encoding="utf-8") as f:
        data = json.load(f)

    random.Random(SEED).shuffle(data)
    if EVAL_COUNT > 0:
        data = data[:EVAL_COUNT]

    results = []
    with cf.ThreadPoolExecutor(max_workers=max(1, WORKERS)) as pool:
        futures = [pool.submit(eval_one, client, item) for item in data]
        for future in tqdm(cf.as_completed(futures), total=len(futures)):
            results.append(future.result())

    results.sort(key=lambda x: x.get("id", 0))
    payload = {
        "input": INPUT_PATH,
        "output": OUTPUT_PATH,
        "model": MODEL,
        "judge_model": JUDGE_MODEL,
        "workers": WORKERS,
        "eval_count": EVAL_COUNT,
        "max_rounds": MAX_ROUNDS,
        "total": len(results),
        "stats": aggregate(results),
        "items": results,
    }

    with open(OUTPUT_PATH, "w", encoding="utf-8") as f:
        json.dump(payload, f, ensure_ascii=False, indent=2)


if __name__ == "__main__":
    main()
